SELECT total_time, execution_time, simd_width, simd_utilization
FROM computing_tasks
WHERE execution_time > 1000;

SELECT SUM(energy_consumption) AS total_energy_consumption
FROM computing_tasks
WHERE energy_consumption > 10.0;

SELECT task_name
FROM computing_tasks
WHERE energy_consumption > (SELECT energy_consumption FROM computing_tasks WHERE task_id = 1);

SELECT COUNT(*) 
FROM computing_tasks 
WHERE simd_width = 8;

SELECT task_name, total_time
FROM computing_tasks
ORDER BY total_time DESC;

SELECT AVG(execution_time) AS avg_execution_time_over_10
FROM computing_tasks
WHERE execution_time > 10;

SELECT task_name
FROM computing_tasks
WHERE total_time = (SELECT MAX(total_time) FROM computing_tasks);

SELECT COUNT(*) AS num_tasks_above_avg
FROM computing_tasks
WHERE execution_time > (SELECT AVG(execution_time) FROM computing_tasks);

SELECT task_name, energy_consumption
FROM computing_tasks
WHERE execution_time > (SELECT AVG(execution_time) FROM computing_tasks);

SELECT AVG(usage) AS average_cpu_usage
FROM cluster_resources
WHERE resource_type = 'CPU';
